     1→"use client";
     2→
     3→import { useState } from "react";
     4→import type { FC, ReactNode } from "react";
     5→
     6→import { cn } from "../../lib/ui/cn";
     7→
     8→interface ProfileMenuItem {
     9→  label: string;
    10→  value: string;
    11→  icon?: ReactNode;
    12→}
    13→
    14→interface ProfileMenuProps {
    15→  items: ProfileMenuItem[];
    16→  value: string;
    17→  onChange: (value: string) => void;
    18→  showBidderToggle?: boolean;
    19→  isBidder?: boolean;
    20→  onBidderToggle?: (value: boolean) => void;
    21→  className?: string;
    22→}
    23→
    24→export const ProfileMenu: FC<ProfileMenuProps> = ({
    25→  items,
    26→  value,
    27→  onChange,
    28→  showBidderToggle = false,
    29→  isBidder = false,
    30→  onBidderToggle,
    31→  className,
    32→}) => {
    33→  const [localBidder, setLocalBidder] = useState(isBidder);
    34→
    35→  const handleToggle = () => {
    36→    const newValue = !localBidder;
    37→    setLocalBidder(newValue);
    38→    onBidderToggle?.(newValue);
    39→  };
    40→
    41→  return (
    42→    <div
    43→      className={cn(
    44→        "w-[270px] rounded-xl bg-white p-3 shadow-[0px_0px_8px_0px_rgba(0,0,0,0.08)]",
    45→        className,
    46→      )}
    47→    >
    48→      <div className="flex flex-col">
    49→        {items.map((item) => {
    50→          const isActive = item.value === value;
    51→
    52→          return (
    53→            <button
    54→              key={item.value}
    55→              type="button"
    56→              onClick={() => onChange(item.value)}
    57→              className={cn(
    58→                "flex items-center gap-2 rounded-lg bg-[#F7F8F9] px-2.5 py-2.5 text-left font-sans text-lg leading-[1.36em] transition-colors",
    59→                isActive
    60→                  ? "border border-[rgba(16,16,16,0.04)] font-semibold text-foreground"
    61→                  : "font-normal text-[#4B5563]",
    62→              )}
    63→            >
    64→              {item.icon}
    65→              <span>{item.label}</span>
    66→            </button>
    67→          );
    68→        })}
    69→      </div>
    70→
    71→      {showBidderToggle && (
    72→        <div className="mt-3 flex items-center gap-10 rounded-[10px] border border-primary px-5 py-2.5">
    73→          <span className="flex-1 font-bold font-serif text-base text-foreground leading-[1.199em]">
    74→            Become a Bidder
    75→          </span>
    76→          <button
    77→            type="button"
    78→            onClick={handleToggle}
    79→            className={cn(
    80→              "relative h-[17px] w-[29px] rounded-full border-[0.5px] border-primary transition-colors",
    81→              localBidder ? "bg-primary" : "bg-white",
    82→            )}
    83→            aria-label="Toggle bidder status"
    84→          >
    85→            <div
    86→              className={cn(
    87→                "absolute top-[1px] size-[15px] rounded-full bg-primary shadow-[0px_2.5px_0.84px_0px_rgba(0,0,0,0.06),0px_2.5px_6.71px_0px_rgba(0,0,0,0.15)] transition-transform",
    88→                localBidder ? "left-[13px]" : "left-[1px]",
    89→              )}
    90→            />
    91→          </button>
    92→        </div>
    93→      )}
    94→    </div>
    95→  );
    96→};
