     8→import { APP_ROUTES } from "@/shared/config/app-routes";
     9→import { UserRole } from "@/shared/types";
    10→import { Popover, PopoverContent, PopoverTrigger } from "@/shared/ui/popover";
    11→import { Separator } from "@/shared/ui/separator";
    12→import Link from "next/link";
    13→
    14→export const ProfilePopover: FC = () => {
    15→  const router = useRouter();
    16→  const { data: session } = useSession();
    17→  const [open, setOpen] = useState(false);
    18→
    19→  const profile = session?.user?.profile;
    20→  const isAdmin = !!profile?.admin;
    21→  const selectedRole = profile?.selectedRole;
    22→
    23→  const handleLogout = async () => {
    24→    await signOut({ redirect: false });
    25→    router.push(APP_ROUTES.AUTH.SIGN_IN);
    26→    router.refresh();
    27→  };
    28→
    29→  return (
    30→    <Popover open={open} onOpenChange={setOpen}>
    31→      <PopoverTrigger asChild>
    32→        <button
    33→          type="button"
    34→          className="flex size-10 items-center justify-center transition-opacity hover:opacity-70"
    35→          aria-label="Profile"
    36→        >
    37→          <Image
    38→            src="/mock-images/user-circle.svg"
    39→            alt="Profile icon"
    40→            width={40}
    41→            height={40}
    42→          />
    43→        </button>
    44→      </PopoverTrigger>
    45→      <PopoverContent
    46→        align="end"
    47→        sideOffset={8}
    48→        className="z-[100] w-[440px] rounded-xl border border-border bg-white p-5 shadow-[0px_0px_8px_0px_rgba(0,0,0,0.08)]"
    49→      >
    50→        <div className="flex flex-col gap-4">
    51→          <Link
    52→            href={APP_ROUTES.PROFILE}
    53→            onClick={() => setOpen(false)}
    54→            className="flex items-center gap-3 rounded-lg border border-transparent p-3 transition-all hover:border-primary hover:bg-secondary/10"
    55→          >
    56→            <div className="flex size-[50px] shrink-0 items-center justify-center rounded-full bg-secondary/20">
    57→              <Image
    58→                src="/mock-images/user-circle.svg"
    59→                alt="Profile icon"
    60→                width={32}
    61→                height={32}
    62→              />
    63→            </div>
    64→            <div className="flex flex-1 flex-col gap-1">
    65→              <h3 className="font-bold font-serif text-foreground text-lg leading-[1.199em]">
    66→                {profile?.fullName || "User"}
    67→              </h3>
    68→              <span className="font-serif text-primary text-sm underline">
    69→                View{" "}
    70→                {profile?.selectedRole === UserRole.SUPER_ADMIN ||
    71→                profile?.selectedRole === UserRole.ADMIN
    72→                  ? "Dashboard"
    73→                  : "Profile"}{" "}
    74→                →
    75→              </span>
    76→            </div>
    77→          </Link>
    78→
    79→          <Separator className="h-px w-full bg-border" />
    80→
    81→          <div className="flex flex-col gap-2">
    82→            <span className="font-serif text-foreground text-sm">
    83→              {isAdmin ? "Admin" : selectedRole || "User"}
    84→            </span>
    85→            <span className="truncate font-serif text-foreground text-sm">
    86→              {profile?.email || ""}
    87→            </span>
    88→          </div>
    89→
    90→          <button
    91→            type="button"
    92→            onClick={handleLogout}
    93→            className="w-full text-left font-serif text-base text-foreground transition-opacity hover:opacity-70"
    94→          >
    95→            Logout
    96→          </button>
    97→        </div>
    98→      </PopoverContent>
    99→    </Popover>
   100→  );
   101→};
